// Helper JSON parser/tokenizer in C
typedef struct {
    char* s;
    int pos;
    int len;
} Tok;

static void skipWS(Tok* t) {
    while (t->pos < t->len && (t->s[t->pos] == ' ' || t->s[t->pos] == ',' || t->s[t->pos] == '\t' || t->s[t->pos] == '\n' || t->s[t->pos] == '\r')) {
        t->pos++;
    }
}

static char* nextToken(Tok* t) {
    skipWS(t);
    if (t->pos >= t->len) return NULL;
    int start = t->pos;
    if (t->s[t->pos] == '[') {
        int depth = 0;
        while (t->pos < t->len) {
            char c = t->s[t->pos++];
            if (c == '[') depth++;
            else if (c == ']') {
                depth--;
                if (depth == 0) break;
            }
        }
        int token_len = t->pos - start;
        char* token = (char*)malloc(token_len + 1);
        strncpy(token, t->s + start, token_len);
        token[token_len] = '\0';
        return token;
    } else if (t->s[t->pos] == '"') {
        t->pos++;
        while (t->pos < t->len && t->s[t->pos] != '"') t->pos++;
        t->pos++;
        int token_len = t->pos - start;
        char* token = (char*)malloc(token_len + 1);
        strncpy(token, t->s + start, token_len);
        token[token_len] = '\0';
        return token;
    } else {
        while (t->pos < t->len && t->s[t->pos] != ',' && t->s[t->pos] != ']' && t->s[t->pos] != '[') t->pos++;
        int token_len = t->pos - start;
        char* token = (char*)malloc(token_len + 1);
        strncpy(token, t->s + start, token_len);
        token[token_len] = '\0';
        int idx = token_len - 1;
        while (idx >= 0 && token[idx] == ' ') {
            token[idx] = '\0';
            idx--;
        }
        return token;
    }
}

static int parse_int(Tok* t) {
    char* tok = nextToken(t);
    if (!tok) return 0;
    int val = atoi(tok);
    free(tok);
    return val;
}

static bool parse_bool(Tok* t) {
    char* tok = nextToken(t);
    if (!tok) return false;
    bool val = (strcmp(tok, "true") == 0);
    free(tok);
    return val;
}

static double parse_double(Tok* t) {
    char* tok = nextToken(t);
    if (!tok) return 0.0;
    double val = atof(tok);
    free(tok);
    return val;
}

static char* parse_string(Tok* t) {
    char* tok = nextToken(t);
    if (!tok) return NULL;
    if (tok[0] == '"') {
        int len = strlen(tok);
        char* res = (char*)malloc(len - 1);
        strncpy(res, tok + 1, len - 2);
        res[len - 2] = '\0';
        free(tok);
        return res;
    }
    return tok;
}

static int* parse_int_array(Tok* t, int* out_size) {
    char* tok = nextToken(t);
    if (!tok || strcmp(tok, "[]") == 0) {
        if (tok) free(tok);
        *out_size = 0;
        return NULL;
    }
    int len = strlen(tok);
    char* inner = (char*)malloc(len - 1);
    strncpy(inner, tok + 1, len - 2);
    inner[len - 2] = '\0';
    free(tok);

    int size = 1;
    for (int i = 0; inner[i]; i++) {
        if (inner[i] == ',') size++;
    }
    int* arr = (int*)malloc(size * sizeof(int));
    Tok t2 = { inner, 0, (int)strlen(inner) };
    for (int i = 0; i < size; i++) {
        arr[i] = parse_int(&t2);
    }
    free(inner);
    *out_size = size;
    return arr;
}

static int** parse_int_2d(Tok* t, int* out_rows, int** out_cols) {
    char* tok = nextToken(t);
    if (!tok || strcmp(tok, "[]") == 0) {
        if (tok) free(tok);
        *out_rows = 0;
        *out_cols = NULL;
        return NULL;
    }
    int len = strlen(tok);
    char* inner = (char*)malloc(len - 1);
    strncpy(inner, tok + 1, len - 2);
    inner[len - 2] = '\0';
    free(tok);

    int rows = 0;
    int depth = 0;
    for (int i = 0; inner[i]; i++) {
        if (inner[i] == '[') {
            if (depth == 0) rows++;
            depth++;
        } else if (inner[i] == ']') {
            depth--;
        }
    }
    int** mat = (int**)malloc(rows * sizeof(int*));
    int* cols = (int*)malloc(rows * sizeof(int));

    Tok t2 = { inner, 0, (int)strlen(inner) };
    for (int i = 0; i < rows; i++) {
        mat[i] = parse_int_array(&t2, &cols[i]);
    }
    free(inner);
    *out_rows = rows;
    *out_cols = cols;
    return mat;
}

